import argparse
import json
import os
from pathlib import Path

import numpy as np
import pandas as pd
import yaml
from lifelines import CoxPHFitter
from lifelines.utils import concordance_index
from sklearn.decomposition import PCA
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import StandardScaler


def load_config(config_path: str) -> dict:
    with open(config_path, "r") as f:
        cfg = yaml.safe_load(f)
    return cfg


def load_data(gene_path: str):
    df = pd.read_csv(gene_path, index_col=0)
    required_cols = {"OS.time", "OS"}
    if not required_cols.issubset(df.columns):
        raise ValueError(f"Expected survival columns {required_cols} in {gene_path}")

    times = df["OS.time"].astype(float)
    events = df["OS"].astype(int)
    X_genes = df.drop(columns=["OS.time", "OS"])
    return X_genes, times, events


def load_clinical(clinical_path: str):
    df = pd.read_csv(clinical_path, index_col=0)
    return df


def reduce_dimensionality(X_train, X_test, n_components, random_seed):
    scaler = StandardScaler()
    X_train_scaled = scaler.fit_transform(X_train)
    X_test_scaled = scaler.transform(X_test)

    if n_components is None:
        n_components = min(50, X_train_scaled.shape[1], X_train_scaled.shape[0] - 1)

    if n_components < 1:
        raise ValueError("n_components must be >= 1")

    pca = PCA(n_components=n_components, random_state=random_seed)
    X_train_pca = pca.fit_transform(X_train_scaled)
    X_test_pca = pca.transform(X_test_scaled)

    train_cols = [f"PC{i + 1}" for i in range(X_train_pca.shape[1])]
    test_cols = train_cols

    X_train_pca = pd.DataFrame(X_train_pca, index=X_train.index, columns=train_cols)
    X_test_pca = pd.DataFrame(X_test_pca, index=X_test.index, columns=test_cols)
    return X_train_pca, X_test_pca, pca


def assemble_dataframe(X, times, events, clinical_df=None):
    df = X.copy()
    df["OS.time"] = times
    df["OS"] = events
    if clinical_df is not None:
        df = df.join(clinical_df)
    return df


def fit_cox_ph(train_df, duration_col, event_col):
    cph = CoxPHFitter()
    cph.fit(train_df, duration_col=duration_col, event_col=event_col, show_progress=False)
    return cph


def evaluate_model(cph, test_df, duration_col, event_col):
    risk_scores = cph.predict_partial_hazard(test_df).values.flatten()
    cindex = concordance_index(test_df[duration_col].values, -risk_scores, test_df[event_col].values)
    return cindex, risk_scores


def save_results(results: dict, output_dir: str):
    output_path = Path(output_dir)
    output_path.mkdir(parents=True, exist_ok=True)
    with open(output_path / "baseline_coxph_results.json", "w") as f:
        json.dump(results, f, indent=2)


def save_summary(cph, model_name: str, output_dir: str):
    summary = cph.summary.copy()
    summary["hazard_ratio"] = np.exp(summary["coef"])
    summary["hr_lower_95"] = np.exp(summary["coef"] - 1.96 * summary["se(coef)"])
    summary["hr_upper_95"] = np.exp(summary["coef"] + 1.96 * summary["se(coef)"])
    summary = summary[["coef", "se(coef)", "z", "p", "hazard_ratio", "hr_lower_95", "hr_upper_95"]]
    summary.to_csv(Path(output_dir) / f"baseline_coxph_summary_{model_name}.csv")


def train_and_save_model(model_name: str, train_df: pd.DataFrame, test_df: pd.DataFrame, output_dir: str):
    cph = fit_cox_ph(train_df, duration_col="OS.time", event_col="OS")
    cindex, _ = evaluate_model(cph, test_df, duration_col="OS.time", event_col="OS")
    save_summary(cph, model_name, output_dir)

    return {
        "model": model_name,
        "n_features": int(train_df.shape[1] - 2),
        "n_train": int(train_df.shape[0]),
        "n_test": int(test_df.shape[0]),
        "c_index": float(cindex),
        "coefficients": cph.params_.to_dict(),
    }


def main():
    parser = argparse.ArgumentParser(description="Simple PCA + CoxPH baseline using gene and clinical data")
    parser.add_argument("--config", type=str, default="../configs/model_config.yaml", help="Path to config YAML")
    parser.add_argument("--n_components", type=int, default=50, help="Number of PCA components")
    parser.add_argument(
        "--models",
        nargs="+",
        choices=["gene", "clinical", "combined"],
        default=["gene", "clinical", "combined"],
        help="Models to train: gene, clinical, combined",
    )
    parser.add_argument("--test_size", type=float, default=0.2, help="Fraction of data reserved for test")
    parser.add_argument("--output_dir", type=str, default="../experiments/runs/baseline_coxph", help="Directory to save baseline results")
    parser.add_argument("--random_seed", type=int, default=42, help="Random seed for splitting and PCA")
    args = parser.parse_args()

    cfg = load_config(args.config)
    gene_path = cfg["data"]["gene_data_path"]
    clinical_path = cfg["data"].get("clinical_data_path")

    X_genes, times, events = load_data(gene_path)
    clinical_df = None
    if "clinical" in args.models or "combined" in args.models:
        if clinical_path is None:
            raise ValueError("clinical_data_path is required in config when clinical or combined models are requested")
        clinical_df = load_clinical(clinical_path)
        if not clinical_df.index.equals(X_genes.index):
            raise ValueError("Index mismatch between gene and clinical data")

    train_index, test_index = train_test_split(
        X_genes.index,
        test_size=args.test_size,
        stratify=events,
        random_state=args.random_seed,
    )

    train_index = pd.Index(train_index)
    test_index = pd.Index(test_index)
    X_train = X_genes.loc[train_index]
    X_test = X_genes.loc[test_index]
    times_train = times.loc[train_index]
    times_test = times.loc[test_index]
    events_train = events.loc[train_index]
    events_test = events.loc[test_index]

    X_train_pca, X_test_pca, pca = reduce_dimensionality(X_train, X_test, args.n_components, args.random_seed)

    model_results = []
    output_dir = os.path.abspath(args.output_dir)

    if "gene" in args.models:
        train_df = assemble_dataframe(X_train_pca, times_train, events_train)
        test_df = assemble_dataframe(X_test_pca, times_test, events_test)
        model_results.append(train_and_save_model("gene", train_df, test_df, output_dir))

    if "clinical" in args.models:
        if clinical_df is None:
            raise ValueError("Clinical data is required for clinical-only model")
        train_df = assemble_dataframe(clinical_df.loc[train_index], times_train, events_train)
        test_df = assemble_dataframe(clinical_df.loc[test_index], times_test, events_test)
        model_results.append(train_and_save_model("clinical", train_df, test_df, output_dir))

    if "combined" in args.models:
        if clinical_df is None:
            raise ValueError("Clinical data is required for combined model")
        X_train_combined = X_train_pca.join(clinical_df.loc[train_index])
        X_test_combined = X_test_pca.join(clinical_df.loc[test_index])
        train_df = assemble_dataframe(X_train_combined, times_train, events_train)
        test_df = assemble_dataframe(X_test_combined, times_test, events_test)
        model_results.append(train_and_save_model("combined", train_df, test_df, output_dir))

    save_results({"models": model_results}, output_dir)

    print("CoxPH baseline completed")
    print(f"  gene data: {gene_path}")
    print(f"  trained models: {', '.join(args.models)}")
    print(f"  output directory: {output_dir}")
    for result in model_results:
        print(f"  {result['model']} C-index: {result['c_index']:.4f} (features: {result['n_features']})")
    print("  Summary CSVs:")
    for result in model_results:
        print(f"    baseline_coxph_summary_{result['model']}.csv")
    print("  Results JSON: baseline_coxph_results.json")


if __name__ == "__main__":
    main()
